sql:
SELECT name, email 
FROM analysts 
WHERE email IN (SELECT email FROM traders);

SELECT s.name, dp.close
FROM stocks s
JOIN daily_prices dp ON s.stock_id = dp.stock_id
WHERE dp.date = (
    SELECT MAX(date) FROM daily_prices
);

SELECT s.name, dp.open, dp.high, dp.low, dp.close, dp.volume
FROM stocks s
JOIN daily_prices dp ON s.stock_id = dp.stock_id
WHERE dp.volume = (
    SELECT MAX(volume) FROM daily_prices
);
